# Allowed origins - explicitly listed for security
ALLOWED_ORIGINS = [
    "https://myapp.example.com",
    "https://staging.myapp.example.com",
    "https://preview.myapp.example.com",
]

# In development, allow localhost origins (controlled via environment variable)
import os
if os.environ.get("ALLOW_DEV_ORIGINS", "false").lower() == "true":
    ALLOWED_ORIGINS.extend([
        "http://localhost:3000",
        "http://localhost:5173",
        "http://localhost:8080",
    ])


def get_cors_headers(request_origin):
    """
    Return CORS headers only if the request origin is in the allowed list.
    This prevents arbitrary origins from making credentialed cross-origin requests.
    
    Using Access-Control-Allow-Origin: * is insecure because:
    - It allows any website to make requests to this API
    - Combined with sensitive data responses, it enables data exfiltration
    - Attackers can craft malicious pages that call this API on behalf of users
    """
    headers = {
        "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization",
        "Access-Control-Max-Age": "3600",
        "Vary": "Origin",
    }

    if request_origin in ALLOWED_ORIGINS:
        headers["Access-Control-Allow-Origin"] = request_origin
        headers["Access-Control-Allow-Credentials"] = "true"
    # If origin is not allowed, we simply don't set Access-Control-Allow-Origin,
    # which causes the browser to block the cross-origin response.

    return headers


@functions_framework.http
def handle_request(request):
    """
    Main HTTP Cloud Function entry point with secure CORS handling.
    """
    request_origin = request.headers.get("Origin", "")
    cors_headers = get_cors_headers(request_origin)

